var TimeMap = function() {
    this.times = new Map();
    this.vals = new Map();
};
TimeMap.prototype.set = function(key, value, timestamp) {
    if (!this.times.has(key)) { this.times.set(key, []); this.vals.set(key, []); }
    this.times.get(key).push(timestamp);
    this.vals.get(key).push(value);
};
TimeMap.prototype.get = function(key, timestamp) {
    if (!this.times.has(key)) return '';
    const ts = this.times.get(key);
    let lo = 0, hi = ts.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (ts[mid] <= timestamp) lo = mid + 1; else hi = mid;
    }
    if (lo === 0) return '';
    return this.vals.get(key)[lo - 1];
};
